import './App.css';
import React, { lazy, useEffect, useState, Profiler } from 'react';
import { HashRouter, Route, getRouterObserve } from 'react-alive-router';

const Pagea = lazy(() => import('./pages/pagea'));
const Rule = lazy(() => import('./pages/rule'));
const Information = lazy(() => import('./pages/information'));
const Lottery = lazy(() => import('./pages/lottery'));
const RaceModeList = lazy(() => import('./pages/race-mode-list'));
const RaceModeDetail = lazy(() => import('./pages/race-mode-detail'));
const RaceModeScene = lazy(() => import('./pages/race-mode-scene'));
const RaceModeQa = lazy(() => import('./pages/race-mode-qa'));
const RaceStatus = lazy(() => import('./pages/race-status'));

function App() {
  // 获取用于路由缓存的key值
  const getPageKey = (rt) => {
    return 'default';
  };
  return (
    <>
      <HashRouter>
        <Route name="index" path="/" component={Pagea} getPageKey={getPageKey} />
        <Route name="rule" path="/rule" component={Rule} getPageKey={getPageKey} />
        <Route name="information" path="/information" component={Information} getPageKey={getPageKey} />
        <Route name="lottery" path="/lottery" component={Lottery} getPageKey={getPageKey} />
        <Route name="race-mode-list" path="/race-mode-list" component={RaceModeList} getPageKey={getPageKey} />
        <Route name="race-mode-detail" path="/race-mode-detail" component={RaceModeDetail} getPageKey={getPageKey} />
        <Route name="race-mode-scene" path="/race-mode-scene" component={RaceModeScene} getPageKey={getPageKey} />
        <Route name="race-mode-qa" path="/race-mode-qa" component={RaceModeQa} getPageKey={getPageKey} />
        <Route name="race-status" path="/race-status" component={RaceStatus} getPageKey={getPageKey} />
      </HashRouter>
      {/* <div>bbb</div> */}
    </>
  );
}

export default App;
